import os
import sys
import json
import argparse
import torch
from pathlib import Path
from typing import Dict, Any
import numpy as np
from PIL import Image
from lerobot.policies.pi0 import PI0Policy
from lerobot.policies.factory import make_pre_post_processors
from VLABench.evaluation.evaluator.base import Evaluator
os.environ['HF_HUB_OFFLINE'] = '1'
class PI0Agent:
    def __init__(self, checkpoint_path: str = None):
        self.name = 'pi0_base_adapter'
        self.control_mode = 'ee'
        self.device = torch.device('cuda' if torch.cuda.is_available() else 'cpu')
        print(f'Loading PI0 on {self.device}')
        self.policy = PI0Policy.from_pretrained('lerobot/pi0_base').to(self.device)
        self.policy.eval()
        self.preprocess, self.postprocess = make_pre_post_processors(
            self.policy.config,
            'lerobot/pi0_base',
            preprocessor_overrides={'device_processor': {'device': str(self.device)}}
        )
        self.reset()
        print('PI0Agent initialized successfully')
    def reset(self):
        self.pending_actions = None
        self.action_chunk_idx = 0
    def _to_device(self, batch: Any, device: torch.device):
        if isinstance(batch, dict):
            return {k: self._to_device(v, device) for k, v in batch.items()}
        elif isinstance(batch, torch.Tensor):
            return batch.to(device)
        elif isinstance(batch, list) and len(batch) > 0 and isinstance(batch[0], torch.Tensor):
            return [x.to(device) for x in batch]
        return batch
    def predict(self, observation: Dict[str, Any], **kwargs):
        try:
            instruction = observation.get('instruction', '')
            rgb = observation.get('rgb')
            if isinstance(rgb, np.ndarray) and rgb.ndim == 4 and rgb.shape[0] >= 4:
                view_indices = [0, 2, 3]
                view_names = ['base_0_rgb', 'left_wrist_0_rgb', 'right_wrist_0_rgb']
                images = {}
                for name, idx in zip(view_names, view_indices):
                    img_array = rgb[idx]
                    if img_array.dtype != np.uint8:
                        img_array = (img_array * 255).clip(0, 255).astype(np.uint8)
                    img_pil = Image.fromarray(img_array)
                    img_pil = img_pil.resize((224, 224), Image.BILINEAR)
                    images[name] = img_pil
            else:
                images = {}
                dummy = Image.new('RGB', (224, 224), color='gray')
                for name in ['base_0_rgb', 'left_wrist_0_rgb', 'right_wrist_0_rgb']:
                    images[name] = dummy
            state = observation.get('ee_state', np.zeros(8, dtype=np.float32))
            if isinstance(state, np.ndarray):
                state = torch.from_numpy(state).float().unsqueeze(0)
            else:
                state = torch.zeros(1, 8, dtype=torch.float32)
            if state.shape[1] < 32:
                padding = torch.zeros(1, 32 - state.shape[1], dtype=state.dtype)
                state = torch.cat([state, padding], dim=1)
            batch = {
                'observation': {
                    'images': images,
                    'state': state,
                },
                'complementary_data': {
                    'task': instruction
                }
            }
            batch = self.preprocess(batch)
            batch = self._to_device(batch, self.device)
            if self.pending_actions is None or self.action_chunk_idx >= self.pending_actions.shape[0]:
                with torch.no_grad():
                    action_chunk = self.policy.predict_action_chunk(batch)
                self.pending_actions = action_chunk.squeeze(0).cpu().numpy() if torch.is_tensor(action_chunk) else np.asarray(action_chunk)
                self.action_chunk_idx = 0
            action = self.pending_actions[self.action_chunk_idx]
            self.action_chunk_idx += 1
            if len(action) > 7:
                action = action[:7]
            ee_state = np.asarray(observation.get('ee_state', np.zeros(8, dtype=np.float32)))
            current_pos = ee_state[:3].astype(np.float32)
            pos = current_pos + action[0:3].astype(np.float32) * 0.05
            euler = (action[3:6] * 0.5).astype(np.float32)
            grip_val = np.clip(float(action[6] if len(action) > 6 else 0.0), -1.0, 1.0)
            gripper = np.array([grip_val, grip_val], dtype=np.float32)
            return (pos, euler, gripper)
        except Exception as e:
            print('Predict error:', str(e))
            import traceback
            traceback.print_exc()
            current_ee = np.asarray(observation.get('ee_state', np.zeros(8)))
            return (current_ee[:3].astype(np.float32), np.zeros(3, dtype=np.float32), np.array([0.0, 0.0], dtype=np.float32))
class RecordingEvaluator(Evaluator):
    def __init__(self, tasks=None, n_episodes=None, episode_config=None, **kwargs):
        super().__init__(tasks=tasks, n_episodes=n_episodes, episode_config=episode_config, **kwargs)
        self.episode_results = []
    def evaluate(self, agent):
        results = {}
        for task_idx, task in enumerate(self.tasks):
            results[task] = {'success_rate': 0.0}
            task_success = 0
            n_eps = self.n_episodes
            for i in range(n_eps):
                try:
                    episode_cfg = self.episode_config[task][i] if isinstance(self.episode_config, dict) and task in self.episode_config else {}
                    info = self.evaluate_single_episode(
                        agent, task, i, episode_cfg, max_episode_length=getattr(self, 'max_steps_per_episode', 300)
                    )
                    success = info.get('success', False) if isinstance(info, dict) else bool(info)
                    if success:
                        task_success += 1
                    self.episode_results.append({
                        'task': task,
                        'episode_index': i,
                        'success': bool(success)
                    })
                except Exception as e:
                    print(f'Error in task {task} episode {i}: {e}')
                    self.episode_results.append({
                        'task': task,
                        'episode_index': i,
                        'success': False
                    })
            results[task]['success_rate'] = task_success / n_eps
        return results
if __name__ == '__main__':
    parser = argparse.ArgumentParser()
    parser.add_argument('--data_path', type=str, required=True)
    parser.add_argument('--checkpoint', type=str, required=True)
    parser.add_argument('--output', type=str, required=True)
    args = parser.parse_args()
    agent = PI0Agent(args.checkpoint)
    eval_config_path = Path(args.data_path) / 'eval_config.json'
    with open(eval_config_path, 'r') as f:
        eval_config = json.load(f)
    evaluator = RecordingEvaluator(
        tasks=eval_config.get('benchmark_tasks', ['add_condiment', 'select_fruit', 'select_book']),
        n_episodes=eval_config.get('episodes_per_task', 20),
        episode_config=eval_config.get('eval_track_path'),
        visualization=False,
        eval_unseen=False,
        metrics=['success_rate']
    )
    print('Starting evaluation with', len(evaluator.tasks), 'tasks')
    results = evaluator.evaluate(agent)
    output_path = Path(args.output)
    output_path.parent.mkdir(parents=True, exist_ok=True)
    output_data = {
        'episodes': getattr(evaluator, 'episode_results', []),
        'total_episodes': len(getattr(evaluator, 'episode_results', []))
    }
    with open(output_path, 'w') as f:
        json.dump(output_data, f, indent=2)
    print('Evaluation completed. Results:', results)
    print('Output saved to', args.output)
